#!/bin/bash
IFS=. read a b c d <<< "$1"; m=$2; s=$((32-m)); IFS=. read m1 m2 m3 m4 <<< "$(printf "%d.%d.%d.%d" $(( (0xFFFFFFFF << s >> 24) & 255 )) $(( (0xFFFFFFFF << s >> 16) & 255 )) $(( (0xFFFFFFFF << s >> 8) & 255 )) $(( (0xFFFFFFFF << s) & 255 )))"; n1=$((a&m1)); n2=$((b&m2)); n3=$((c&m3)); n4=$((d&m4)); b1=$((n1|(~m1&255))); b2=$((n2|(~m2&255))); b3=$((n3|(~m3&255))); b4=$((n4|(~m4&255))); echo "$n1.$n2.$n3.$((n4+1)) - $b1.$b2.$b3.$((b4-1))"
